const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:3001/api/v1";
async function fetchApi(path, init) {
    const res = await fetch(`${API_URL}${path}`, {
        ...init,
        headers: {
            "Content-Type": "application/json",
            ...init?.headers
        }
    });
    if (!res.ok) {
        const err = await res.json().catch(()=>({
                error: res.statusText
            }));
        throw new Error(err.error || res.statusText);
    }
    return res.json();
}
async function getCitizens() {
    return fetchApi("/citizens");
}
async function getCitizen(ensName) {
    return fetchApi(`/citizens/${encodeURIComponent(ensName)}`);
}
async function getFeed(limit = 20) {
    return fetchApi(`/feed?limit=${limit}`);
}
async function getStats() {
    return fetchApi("/stats");
}
async function getDemoAgents() {
    return fetchApi("/demo/agents");
}
async function demoResearch(token) {
    return fetchApi("/demo/research", {
        method: "POST",
        body: JSON.stringify({
            token
        })
    });
}
async function demoSwap(fromToken, toToken, amount) {
    return fetchApi("/demo/swap", {
        method: "POST",
        body: JSON.stringify({
            fromToken,
            toToken,
            amount
        })
    });
}
async function demoHire(serviceId) {
    return fetchApi("/demo/hire", {
        method: "POST",
        body: JSON.stringify({
            service_id: serviceId
        })
    });
}
